sql:
SELECT election_id, COUNT(*) as total_measures
FROM measures
GROUP BY election_id;

SELECT election_name
FROM elections
WHERE election_type = 'General' AND total_registered_voters > 500000;

SELECT elections.election_name, jurisdictions.jurisdiction_name
FROM elections
INNER JOIN jurisdictions ON elections.jurisdiction_id = jurisdictions.jurisdiction_id;

SELECT election_name, election_date, election_type, total_registered_voters, voter_turnout_percentage
FROM elections
WHERE election_type = 'Special Ballot' AND voter_turnout_percentage > 70;

SELECT measure_name 
FROM measures 
WHERE vote_count_for > (SELECT AVG(vote_count_for) FROM measures);

SELECT AVG(voter_turnout_percentage) AS average_voter_turnout_percentage
FROM elections
WHERE election_id IN (1, 2);

SELECT election_name 
FROM elections 
WHERE election_id = 1;

external_knowledge:
- 'General elections' refers to the 'General' type of election;
- 'Heroes vying to lead them' refers to the candidates in the election;
- 'Threads of general elections' metaphorically refers to the elections themselves and their jurisdictional context;
- 'State-level decision-making' refers to the elections held at the 'State' level.

sql:
SELECT m.measure_name, vr.votes
FROM measures m
JOIN vote_results vr ON m.measure_id = vr.measure_id;
